class Main {
  // 1. Defining the Inbox (Parameter)
  static void greetPlayer(String playerName) {
    System.out.println("Welcome, " + playerName + "!");
  }

  public static void main(String[] args) {
    // 2. Sending mail into the inbox (Argument)
    greetPlayer("Alex");
    greetPlayer("Sam");
  }
}

class Main {
  // Takes two ints
  static void printSum(int a, int b) {
    int sum = a + b;
    System.out.println("The sum is: " + sum);
  }

  public static void main(String[] args) {
    printSum(5, 10); // Prints 15
    printSum(100, 20); // Prints 120
  }
}
